  ('aboriginal-c5fb3965-moex-00083', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '甲之父為平地原住民，母為山地原住民，有關甲身分之取得，下列敘述何者正確？', '["父母得約定變更為相同身分，而甲從之", "若父母未約定變更為相同身分，甲應從父之平地原住民身分", "若父母未約定變更為相同身分，甲應從母之山地原住民身分", "甲於成年後不得變更父母約定之身分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "ec1e235b5965", "answer_pdf_sha1": "c1e439afad77", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0612", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
