  ('aboriginal-c5fb3965-moex-00087', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '有關國民身分證統一編號重複而應予以重新配賦新號時，下列敘述何者錯誤？', '["統一編號重複當事人之一方自願配賦新號時，得予以重新配賦，並得自行挑選號碼", "統一編號重複之雙方當事人均無意願配賦新號時，由配賦在後者重新配賦新號", "統一編號重複之雙方當事人均無意願配賦新號，且無法分辨配賦之先後時，以抽籤決定何人重新配賦 新號", "統一編號重複當事人之一方有不得變更統一編號之情形時，由他方重新配賦新號"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "ec1e235b5965", "answer_pdf_sha1": "c1e439afad77", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0612", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
